function solve(points, target) {
    // Helper to serialize a point [x, y, z] into a unique string key
    const serialize = (p) => p.join(',');

    const targetStr = serialize(target);

    // allPointsSet tracks all unique points found so far (Generation 0 up to k-1)
    let allPointsSet = new Set();

    // P_list stores the actual coordinate arrays of all unique points found so far, 
    // allowing for easy iteration over available points.
    let P_list = [];

    // Initialize Generation 0
    for (const p of points) {
        const pStr = serialize(p);
        if (!allPointsSet.has(pStr)) {
            allPointsSet.add(pStr);
            P_list.push([...p]); // Store a copy
        }
    }

    // 1. Check Generation 0
    if (allPointsSet.has(targetStr)) {
        return 0;
    }

    let k = 0;

    while (true) {
        k++;
        const newPointsGenerated = [];
        const currentPointsList = P_list;
        const N = currentPointsList.length;

        // Need at least two distinct points to generate a new point
        if (N < 2) {
            break; 
        }

        let foundTargetInThisStep = false;

        // Generate all unique pairs (a, b) from currentPointsList
        // Since P_list contains only unique points, i < j guarantees distinct points.
        for (let i = 0; i < N; i++) {
            for (let j = i + 1; j < N; j++) {
                const p1 = currentPointsList[i];
                const p2 = currentPointsList[j];

                // Calculate the midpoint c = [floor((x1+x2)/2), ...]
                const c = [
                    Math.floor((p1[0] + p2[0]) / 2),
                    Math.floor((p1[1] + p2[1]) / 2),
                    Math.floor((p1[2] + p2[2]) / 2)
                ];

                const cStr = serialize(c);

                // Check if this new point is novel (not already in allPointsSet)
                if (!allPointsSet.has(cStr)) {
                    newPointsGenerated.push(c);

                    // Check if this newly generated point is the target
                    if (cStr === targetStr) {
                        foundTargetInThisStep = true;
                        break; 
                    }
                }
            }
            if (foundTargetInThisStep) break;
        }

        if (foundTargetInThisStep) {
            return k;
        }

        if (newPointsGenerated.length === 0) {
            // No new unique points were generated in this step, and the target wasn't found. Stop.
            break;
        }

        // Update state for the next generation (k+1)
        for (const p of newPointsGenerated) {
            const pStr = serialize(p);
            allPointsSet.add(pStr);
            P_list.push([...p]); // Add the new point to the list of available points
        }
    }

    // If the loop finished without finding the target
    return -1;
}

