import java.util.*;

public class Solution {

    // Helper function to serialize a point [x, y, z] into a unique string key
    private static String serialize(long[] p) {
        return p[0] + "," + p[1] + "," + p[2];
    }

    public static long solve(long[][] points, long[] target) {

        String targetStr = serialize(target);

        // allPointsSet tracks all unique points found so far (Generation 0 up to k-1)
        Set<String> allPointsSet = new HashSet<>();

        // P_list stores the actual coordinate arrays of all unique points found so far, 
        // allowing for easy iteration over available points.
        List<long[]> P_list = new ArrayList<>();

        // Initialize Generation 0
        for (long[] p : points) {
            String pStr = serialize(p);
            if (!allPointsSet.contains(pStr)) {
                allPointsSet.add(pStr);
                P_list.add(p.clone()); // Store a copy
            }
        }

        // 1. Check Generation 0
        if (allPointsSet.contains(targetStr)) {
            return 0;
        }

        int k = 0;

        while (true) {
            k++;
            List<long[]> newPointsGenerated = new ArrayList<>();
            List<long[]> currentPointsList = P_list;
            final int N = currentPointsList.size();

            // Need at least two distinct points to generate a new point
            if (N < 2) {
                break; 
            }

            boolean foundTargetInThisStep = false;

            // Generate all unique pairs (a, b) from currentPointsList
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    long[] p1 = currentPointsList.get(i);
                    long[] p2 = currentPointsList.get(j);

                    // Calculate the midpoint c = [floor((x1+x2)/2), ...]
                    // Integer division in Java automatically performs floor for positive numbers
                    long cX = (p1[0] + p2[0]) / 2;
                    long cY = (p1[1] + p2[1]) / 2;
                    long cZ = (p1[2] + p2[2]) / 2;

                    long[] c = new long[]{cX, cY, cZ};

                    String cStr = serialize(c);

                    // Check if this new point is novel (not already in allPointsSet)
                    if (!allPointsSet.contains(cStr)) {

                        // Check if this newly generated point is the target
                        if (cStr.equals(targetStr)) {
                            foundTargetInThisStep = true;
                            break; // Found target, stop iterating pairs in this step
                        }

                        newPointsGenerated.add(c);
                    }
                }
                if (foundTargetInThisStep) break;
            }

            if (foundTargetInThisStep) {
                return k;
            }

            if (newPointsGenerated.isEmpty()) {
                // No new unique points were generated in this step, and the target wasn't found. Stop.
                break;
            }

            // Update state for the next generation (k+1)
            for (long[] p : newPointsGenerated) {
                String pStr = serialize(p);
                // Since we only added points if they were novel, we just add them
                allPointsSet.add(pStr);
                P_list.add(p.clone()); // Add the new point to the list of available points
            }
        }

        // If the loop finished without finding the target
        return -1;
    }
}

