        return 0;
    }

    // Convert set keys back to point arrays for easier iteration later
    // We store the points as arrays internally to easily access coordinates
    let availablePoints = points.map(p => [...p]); // Use original array structure for k=0
    // We must ensure that the set 'allPointsSet' tracks unique coordinates regardless of how we iterate.

    // Let's switch 'availablePoints' to be the list of actual coordinate arrays 
    // corresponding to the unique entries in allPointsSet.

    // Re-initialize structure to manage point lists vs sets efficiently.
    // S: Set of serialized coordinates (for quick lookups)
    // P_list: Array of coordinate arrays (for iteration)

    allPointsSet.clear();
    let P_list = [];

    for (const p of points) {
        const pStr = serialize(p);
        if (!allPointsSet.has(pStr)) {
            allPointsSet.add(pStr);
            P_list.push([...p]); // Store a copy
        }
