import java.util.*;

public class Solution {

    /**
     * Serializes a point [x, y, z] into a unique string key for use in a Set.
     */
    private static String serialize(long[] p) {
        return p[0] + "," + p[1] + "," + p[2];
    }

    public static long solve(long[][] points, long[] target) {
        // 1. Initialization (Generation 0)

        // Set to track all unique points found so far (Generation 0 up to k-1)
        Set<String> allPointsSet = new HashSet<>();

        // List storing the actual coordinate arrays of all unique points found so far
        List<long[]> pList = new ArrayList<>();

        // Process initial points
        for (long[] p : points) {
            String pStr = serialize(p);
            if (!allPointsSet.contains(pStr)) {
                allPointsSet.add(pStr);
                // Store a copy of the point
                pList.add(Arrays.copyOf(p, 3)); 
            }
        }

        String targetStr = serialize(target);

        // Check Generation 0
        if (allPointsSet.contains(targetStr)) {
            return 0;
        }

        int k = 0;

        // Iterative generation process
        while (true) {
            k++;

            // Points available for pairing are those in pList (Gen 0 up to k-1)
            List<long[]> currentPointsList = pList;
            int N = currentPointsList.size();

            // Need at least two distinct points to generate a new point
            if (N < 2) {
                break; 
            }

            List<long[]> newPointsGenerated = new ArrayList<>();
            boolean foundTargetInThisStep = false;

            // Generate all unique pairs (p1, p2)
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    long[] p1 = currentPointsList.get(i);
                    long[] p2 = currentPointsList.get(j);

                    // Calculate the midpoint c = [floor((x1+x2)/2), ...]
                    long[] c = new long[3];
                    c[0] = (p1[0] + p2[0]) / 2; // Integer division performs floor for non-negative numbers
                    c[1] = (p1[1] + p2[1]) / 2;
                    c[2] = (p1[2] + p2[2]) / 2;

                    String cStr = serialize(c);

                    // Check if this new point is novel
                    if (!allPointsSet.contains(cStr)) {

                        // Check if this newly generated point is the target
                        if (cStr.equals(targetStr)) {
                            return k; 
                        }

                        newPointsGenerated.add(c);
